import React, { useState, useEffect, useCallback } from 'react';
import { studentAPI, schoolAPI } from '../services/api';
import toast from 'react-hot-toast';

// ── CARD THEMES ──────────────────────────────────────────────
const THEMES = {
  classic:  { name:'Classic Blue',   primary:'#1E1B4B', accent:'#7C3AED', bg:'#EDE9F8',   text:'#1E1B4B', light:'rgba(255,255,255,.15)' },
  forest:   { name:'Forest Green',   primary:'#065F46', accent:'#10B981', bg:'#D1FAE5',   text:'#065F46', light:'rgba(255,255,255,.15)' },
  royal:    { name:'Royal Red',      primary:'#7F1D1D', accent:'#EF4444', bg:'#FEE2E2',   text:'#7F1D1D', light:'rgba(255,255,255,.15)' },
  ocean:    { name:'Ocean Blue',     primary:'#1E40AF', accent:'#60A5FA', bg:'#DBEAFE',   text:'#1E40AF', light:'rgba(255,255,255,.15)' },
  golden:   { name:'Golden',         primary:'#78350F', accent:'#F59E0B', bg:'#FEF3C7',   text:'#78350F', light:'rgba(255,255,255,.15)' },
  midnight: { name:'Midnight',       primary:'#0F172A', accent:'#38BDF8', bg:'#E0F2FE',   text:'#0F172A', light:'rgba(255,255,255,.12)' },
};

// ── HORIZONTAL CARDS ─────────────────────────────────────────
function CardH1({ student, theme, school }) {
  const t = THEMES[theme] || THEMES.classic;
  const name = ((student?.first_name||'') + ' ' + (student?.last_name||'')).trim() || 'Student Name';
  return (
    <div style={{width:340,height:210,borderRadius:14,overflow:'hidden',display:'flex',background:'#fff',boxShadow:'0 6px 24px rgba(0,0,0,.18)',fontFamily:'Arial,sans-serif',flexShrink:0}}>
      {/* Left strip */}
      <div style={{width:90,background:t.primary,display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'space-between',padding:'10px 6px'}}>
        <div style={{textAlign:'center'}}>
          {school?.logo && <img src={school.logo} alt="logo" style={{width:40,height:40,objectFit:'contain',borderRadius:6,marginBottom:4}}/>}
          <div style={{fontSize:6,fontWeight:700,color:'rgba(255,255,255,.8)',textTransform:'uppercase',letterSpacing:'.05em',lineHeight:1.3}}>{school?.schoolName||'School'}</div>
        </div>
        <div style={{width:68,height:72,borderRadius:8,background:t.light,overflow:'hidden',border:'2px solid rgba(255,255,255,.3)',display:'flex',alignItems:'center',justifyContent:'center'}}>
          {student?.photo_url ? <img src={student.photo_url} style={{width:'100%',height:'100%',objectFit:'cover'}}/> : <span style={{fontSize:28,color:'rgba(255,255,255,.4)'}}>👤</span>}
        </div>
        <div style={{fontSize:7,color:'rgba(255,255,255,.6)',textAlign:'center'}}>STUDENT ID</div>
      </div>
      {/* Right */}
      <div style={{flex:1,display:'flex',flexDirection:'column',justifyContent:'space-between',padding:'10px 12px'}}>
        <div>
          <div style={{fontSize:6,fontWeight:700,color:t.primary,textTransform:'uppercase',letterSpacing:'.1em',marginBottom:2}}>Student Identity Card</div>
          <div style={{fontSize:16,fontWeight:800,color:'#111827',lineHeight:1.2,marginBottom:6}}>{name}</div>
          <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:'3px 8px'}}>
            {[['Class',student?.class_name||'—'],['Section',student?.section_name||'A'],['Adm No',student?.admission_no||'—'],['Roll No',student?.roll_no||'—'],['DOB',student?.date_of_birth?String(student.date_of_birth).split('T')[0]:'—'],['Blood',student?.blood_group||'—']].map(([k,v])=>(
              <div key={k} style={{lineHeight:1.7}}>
                <span style={{fontSize:8,fontWeight:700,color:'#9CA3AF',textTransform:'uppercase'}}>{k}: </span>
                <span style={{fontSize:9,fontWeight:600,color:'#111827'}}>{v}</span>
              </div>
            ))}
          </div>
          {student?.parent_name && <div style={{marginTop:4,fontSize:9,color:'#6B7280'}}>Parent: <strong>{student.parent_name}</strong></div>}
          {student?.parent_phone && <div style={{fontSize:9,color:'#6B7280'}}>Ph: {student.parent_phone}</div>}
        </div>
        <div style={{borderTop:'1px solid #F3F4F6',paddingTop:6,display:'flex',justifyContent:'space-between',alignItems:'center'}}>
          <div style={{fontSize:7,color:'#9CA3AF'}}>Valid: {new Date().getFullYear()}-{new Date().getFullYear()+1}</div>
          <div style={{width:50,textAlign:'right'}}>
            <div style={{fontSize:7,color:t.primary,fontWeight:700,borderTop:`1px solid ${t.primary}`,paddingTop:2}}>Principal</div>
          </div>
        </div>
      </div>
    </div>
  );
}

function CardH2({ student, theme, school }) {
  const t = THEMES[theme] || THEMES.classic;
  const name = ((student?.first_name||'') + ' ' + (student?.last_name||'')).trim() || 'Student Name';
  return (
    <div style={{width:340,height:210,borderRadius:14,overflow:'hidden',background:'#fff',boxShadow:'0 6px 24px rgba(0,0,0,.18)',fontFamily:'Arial,sans-serif',flexShrink:0,position:'relative'}}>
      {/* Top bar */}
      <div style={{height:54,background:`linear-gradient(135deg,${t.primary},${t.accent})`,padding:'6px 14px',display:'flex',justifyContent:'space-between',alignItems:'center'}}>
        <div>
          {school?.logo && <img src={school.logo} style={{height:28,objectFit:'contain',marginBottom:2}}/>}
          <div style={{fontSize:10,fontWeight:800,color:'#fff',textTransform:'uppercase',letterSpacing:'.04em'}}>{school?.schoolName||'School'}</div>
          <div style={{fontSize:7,color:'rgba(255,255,255,.7)'}}>Student Identity Card</div>
        </div>
        <div style={{width:52,height:52,borderRadius:'50%',background:'rgba(255,255,255,.15)',border:'2px solid rgba(255,255,255,.4)',overflow:'hidden',display:'flex',alignItems:'center',justifyContent:'center'}}>
          {student?.photo_url ? <img src={student.photo_url} style={{width:'100%',height:'100%',objectFit:'cover'}}/> : <span style={{fontSize:22,color:'rgba(255,255,255,.5)'}}>👤</span>}
        </div>
      </div>
      {/* Body */}
      <div style={{padding:'8px 14px'}}>
        <div style={{fontSize:15,fontWeight:800,color:'#111827',marginBottom:4}}>{name}</div>
        <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:'3px 6px',marginBottom:6}}>
          {[['Class',student?.class_name||'—'],['Section',student?.section_name||'A'],['Adm No',student?.admission_no||'—'],['Roll',student?.roll_no||'—'],['Blood',student?.blood_group||'—'],['DOB',student?.date_of_birth?String(student.date_of_birth).split('T')[0]:'—']].map(([k,v])=>(
            <div key={k}><div style={{fontSize:7,color:'#9CA3AF',textTransform:'uppercase',fontWeight:700}}>{k}</div><div style={{fontSize:10,fontWeight:700,color:'#111827'}}>{v}</div></div>
          ))}
        </div>
        {student?.parent_name && <div style={{fontSize:9,color:'#6B7280',marginBottom:2}}>Parent: <strong>{student.parent_name}</strong> {student?.parent_phone && `· ${student.parent_phone}`}</div>}
      </div>
      {/* Bottom */}
      <div style={{position:'absolute',bottom:0,left:0,right:0,height:24,background:t.bg,display:'flex',justifyContent:'space-between',alignItems:'center',padding:'0 14px'}}>
        <div style={{fontSize:7,color:t.text}}>Valid: {new Date().getFullYear()}-{new Date().getFullYear()+1}</div>
        <div style={{fontSize:7,color:t.text,fontWeight:700}}>Principal Signature</div>
      </div>
    </div>
  );
}

function CardH3({ student, theme, school }) {
  const t = THEMES[theme] || THEMES.classic;
  const name = ((student?.first_name||'') + ' ' + (student?.last_name||'')).trim() || 'Student Name';
  return (
    <div style={{width:340,height:210,borderRadius:14,overflow:'hidden',background:t.primary,boxShadow:'0 6px 24px rgba(0,0,0,.25)',fontFamily:'Arial,sans-serif',flexShrink:0}}>
      {/* Dark card style */}
      <div style={{padding:'10px 12px',display:'flex',justifyContent:'space-between',alignItems:'flex-start'}}>
        <div>
          {school?.logo && <img src={school.logo} style={{height:24,objectFit:'contain',filter:'brightness(0) invert(1)',marginBottom:2}}/>}
          <div style={{fontSize:9,fontWeight:700,color:'rgba(255,255,255,.9)',textTransform:'uppercase'}}>{school?.schoolName||'School'}</div>
          <div style={{fontSize:6,color:'rgba(255,255,255,.5)',marginTop:1}}>STUDENT ID CARD</div>
        </div>
        <div style={{width:56,height:60,borderRadius:10,overflow:'hidden',border:`2px solid ${t.accent}`,display:'flex',alignItems:'center',justifyContent:'center',background:'rgba(255,255,255,.1)'}}>
          {student?.photo_url ? <img src={student.photo_url} style={{width:'100%',height:'100%',objectFit:'cover'}}/> : <span style={{fontSize:24,color:'rgba(255,255,255,.3)'}}>👤</span>}
        </div>
      </div>
      <div style={{padding:'0 12px 6px'}}>
        <div style={{fontSize:17,fontWeight:900,color:'#fff',marginBottom:1}}>{name}</div>
        <div style={{display:'flex',gap:6,marginBottom:6,flexWrap:'wrap'}}>
          {[student?.class_name,student?.section_name?'Sec '+student.section_name:null,student?.admission_no].filter(Boolean).map((v,i)=>(
            <span key={i} style={{padding:'2px 8px',background:t.accent,color:'#fff',borderRadius:10,fontSize:9,fontWeight:700}}>{v}</span>
          ))}
        </div>
        <div style={{display:'grid',gridTemplateColumns:'repeat(3,1fr)',gap:'4px',marginBottom:6}}>
          {[['Roll',student?.roll_no||'—'],['Blood',student?.blood_group||'—'],['DOB',student?.date_of_birth?String(student.date_of_birth).split('T')[0].slice(5):'—']].map(([k,v])=>(
            <div key={k} style={{background:'rgba(255,255,255,.08)',borderRadius:6,padding:'3px 6px'}}>
              <div style={{fontSize:6,color:'rgba(255,255,255,.5)',textTransform:'uppercase'}}>{k}</div>
              <div style={{fontSize:10,color:'#fff',fontWeight:700}}>{v}</div>
            </div>
          ))}
        </div>
        {student?.parent_name && <div style={{fontSize:8,color:'rgba(255,255,255,.6)'}}>Parent: {student.parent_name} {student?.parent_phone && `· ${student.parent_phone}`}</div>}
      </div>
      <div style={{borderTop:`1px solid rgba(255,255,255,.1)`,padding:'4px 12px',display:'flex',justifyContent:'space-between'}}>
        <div style={{fontSize:6,color:'rgba(255,255,255,.4)'}}>Valid: {new Date().getFullYear()}-{new Date().getFullYear()+1}</div>
        <div style={{fontSize:6,color:'rgba(255,255,255,.4)'}}>Authorized Signatory</div>
      </div>
    </div>
  );
}

// ── VERTICAL CARDS ───────────────────────────────────────────
function CardV1({ student, theme, school }) {
  const t = THEMES[theme] || THEMES.classic;
  const name = ((student?.first_name||'') + ' ' + (student?.last_name||'')).trim() || 'Student Name';
  return (
    <div style={{width:210,height:320,borderRadius:14,overflow:'hidden',background:'#fff',boxShadow:'0 6px 24px rgba(0,0,0,.18)',fontFamily:'Arial,sans-serif',flexShrink:0,display:'flex',flexDirection:'column'}}>
      {/* Header */}
      <div style={{background:t.primary,padding:'10px 12px',textAlign:'center'}}>
        {school?.logo && <img src={school.logo} style={{height:28,objectFit:'contain',marginBottom:4}}/>}
        <div style={{fontSize:10,fontWeight:800,color:'#fff',textTransform:'uppercase',letterSpacing:'.04em'}}>{school?.schoolName||'School'}</div>
        <div style={{fontSize:6,color:'rgba(255,255,255,.6)',marginTop:1}}>STUDENT IDENTITY CARD</div>
      </div>
      {/* Photo */}
      <div style={{padding:'12px',display:'flex',justifyContent:'center'}}>
        <div style={{width:72,height:80,borderRadius:10,overflow:'hidden',border:`3px solid ${t.primary}`,display:'flex',alignItems:'center',justifyContent:'center',background:t.bg}}>
          {student?.photo_url ? <img src={student.photo_url} style={{width:'100%',height:'100%',objectFit:'cover'}}/> : <span style={{fontSize:32,color:t.primary,opacity:.4}}>👤</span>}
        </div>
      </div>
      {/* Name */}
      <div style={{textAlign:'center',padding:'0 8px 8px'}}>
        <div style={{fontSize:13,fontWeight:800,color:'#111827',lineHeight:1.2}}>{name}</div>
        <div style={{fontSize:9,color:t.primary,fontWeight:700,marginTop:2}}>{student?.class_name||'—'} {student?.section_name?`· Sec ${student.section_name}`:''}</div>
      </div>
      {/* Details */}
      <div style={{flex:1,padding:'0 10px',display:'flex',flexDirection:'column',gap:3}}>
        {[['Adm No',student?.admission_no||'—'],['Roll No',student?.roll_no||'—'],['DOB',student?.date_of_birth?String(student.date_of_birth).split('T')[0]:'—'],['Blood',student?.blood_group||'—'],['Parent',student?.parent_name||'—'],['Phone',student?.parent_phone||'—']].map(([k,v])=>(
          <div key={k} style={{display:'flex',justifyContent:'space-between',borderBottom:'0.5px solid #F3F4F6',paddingBottom:2}}>
            <span style={{fontSize:8,color:'#9CA3AF',fontWeight:700}}>{k}</span>
            <span style={{fontSize:8,fontWeight:700,color:'#111827',maxWidth:100,textAlign:'right',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{v}</span>
          </div>
        ))}
      </div>
      {/* Footer */}
      <div style={{background:t.bg,padding:'6px 10px',textAlign:'center'}}>
        <div style={{fontSize:6,color:t.text,fontWeight:700,borderTop:`1px solid ${t.primary}`,paddingTop:4,display:'inline-block',minWidth:80}}>Principal</div>
        <div style={{fontSize:6,color:t.text,marginTop:1}}>Valid: {new Date().getFullYear()}-{new Date().getFullYear()+1}</div>
      </div>
    </div>
  );
}

function CardV2({ student, theme, school }) {
  const t = THEMES[theme] || THEMES.classic;
  const name = ((student?.first_name||'') + ' ' + (student?.last_name||'')).trim() || 'Student Name';
  return (
    <div style={{width:210,height:320,borderRadius:14,overflow:'hidden',background:t.bg,boxShadow:'0 6px 24px rgba(0,0,0,.18)',fontFamily:'Arial,sans-serif',flexShrink:0,display:'flex',flexDirection:'column'}}>
      {/* Top circle design */}
      <div style={{background:t.primary,padding:'14px 12px 28px',textAlign:'center',position:'relative'}}>
        <div style={{position:'absolute',bottom:-20,left:'50%',transform:'translateX(-50%)',width:72,height:72,borderRadius:'50%',border:`4px solid ${t.bg}`,overflow:'hidden',background:t.bg,display:'flex',alignItems:'center',justifyContent:'center',zIndex:1}}>
          {student?.photo_url ? <img src={student.photo_url} style={{width:'100%',height:'100%',objectFit:'cover',borderRadius:'50%'}}/> : <span style={{fontSize:30,color:t.primary,opacity:.5}}>👤</span>}
        </div>
        {school?.logo && <img src={school.logo} style={{height:22,objectFit:'contain',marginBottom:3,filter:'brightness(0) invert(1)'}}/>}
        <div style={{fontSize:9,fontWeight:800,color:'#fff',textTransform:'uppercase'}}>{school?.schoolName||'School'}</div>
        <div style={{fontSize:6,color:'rgba(255,255,255,.6)'}}>Student ID Card</div>
      </div>
      <div style={{height:32}}/>
      <div style={{textAlign:'center',padding:'0 10px 8px'}}>
        <div style={{fontSize:13,fontWeight:800,color:'#111827'}}>{name}</div>
        <span style={{padding:'2px 10px',background:t.primary,color:'#fff',borderRadius:10,fontSize:8,fontWeight:700}}>
          {student?.class_name||'—'} {student?.section_name?`· ${student.section_name}`:''}
        </span>
      </div>
      <div style={{flex:1,padding:'0 12px',display:'grid',gridTemplateColumns:'1fr 1fr',gap:'4px 8px'}}>
        {[['Adm No',student?.admission_no||'—'],['Roll No',student?.roll_no||'—'],['Blood',student?.blood_group||'—'],['DOB',student?.date_of_birth?String(student.date_of_birth).split('T')[0].slice(2):'—'],['Parent',student?.parent_name||'—'],['Phone',student?.parent_phone||'—']].map(([k,v])=>(
          <div key={k} style={{background:'rgba(255,255,255,.6)',borderRadius:6,padding:'3px 6px'}}>
            <div style={{fontSize:6,color:'#9CA3AF',textTransform:'uppercase',fontWeight:700}}>{k}</div>
            <div style={{fontSize:8,fontWeight:700,color:'#111827',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{v}</div>
          </div>
        ))}
      </div>
      <div style={{background:t.primary,padding:'6px 10px',textAlign:'center',marginTop:6}}>
        <div style={{fontSize:6,color:'rgba(255,255,255,.7)'}}>Valid: {new Date().getFullYear()}-{new Date().getFullYear()+1} · Authorized Signatory</div>
      </div>
    </div>
  );
}

function CardV3({ student, theme, school }) {
  const t = THEMES[theme] || THEMES.classic;
  const name = ((student?.first_name||'') + ' ' + (student?.last_name||'')).trim() || 'Student Name';
  return (
    <div style={{width:210,height:320,borderRadius:14,overflow:'hidden',background:t.primary,boxShadow:'0 6px 24px rgba(0,0,0,.25)',fontFamily:'Arial,sans-serif',flexShrink:0,display:'flex',flexDirection:'column'}}>
      <div style={{padding:'10px 12px',display:'flex',justifyContent:'space-between',alignItems:'center'}}>
        {school?.logo && <img src={school.logo} style={{height:26,objectFit:'contain',filter:'brightness(0) invert(1)'}}/>}
        <div style={{fontSize:6,color:'rgba(255,255,255,.5)',textTransform:'uppercase',textAlign:'right'}}>Student<br/>ID Card</div>
      </div>
      <div style={{display:'flex',justifyContent:'center',padding:'0 0 8px'}}>
        <div style={{width:76,height:86,borderRadius:12,overflow:'hidden',border:`3px solid ${t.accent}`,display:'flex',alignItems:'center',justifyContent:'center',background:'rgba(255,255,255,.1)'}}>
          {student?.photo_url ? <img src={student.photo_url} style={{width:'100%',height:'100%',objectFit:'cover'}}/> : <span style={{fontSize:34,color:'rgba(255,255,255,.3)'}}>👤</span>}
        </div>
      </div>
      <div style={{textAlign:'center',padding:'0 10px 8px'}}>
        <div style={{fontSize:14,fontWeight:900,color:'#fff'}}>{name}</div>
        <div style={{display:'flex',gap:4,justifyContent:'center',marginTop:4,flexWrap:'wrap'}}>
          {[student?.class_name,student?.section_name?'Sec '+student.section_name:null,student?.admission_no].filter(Boolean).map((v,i)=>(
            <span key={i} style={{padding:'2px 8px',background:t.accent,color:'#fff',borderRadius:8,fontSize:8,fontWeight:700}}>{v}</span>
          ))}
        </div>
      </div>
      <div style={{flex:1,padding:'0 10px',display:'flex',flexDirection:'column',gap:4}}>
        {[['Roll No',student?.roll_no||'—'],['Blood',student?.blood_group||'—'],['DOB',student?.date_of_birth?String(student.date_of_birth).split('T')[0]:'—'],['Parent',student?.parent_name||'—'],['Phone',student?.parent_phone||'—']].map(([k,v])=>(
          <div key={k} style={{display:'flex',justifyContent:'space-between',alignItems:'center'}}>
            <span style={{fontSize:7,color:'rgba(255,255,255,.5)',textTransform:'uppercase'}}>{k}</span>
            <span style={{fontSize:8,fontWeight:700,color:'rgba(255,255,255,.9)',maxWidth:110,textAlign:'right',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{v}</span>
          </div>
        ))}
      </div>
      <div style={{borderTop:`1px solid rgba(255,255,255,.1)`,padding:'6px 12px',display:'flex',justifyContent:'space-between'}}>
        <span style={{fontSize:6,color:'rgba(255,255,255,.4)'}}>Valid: {new Date().getFullYear()}-{new Date().getFullYear()+1}</span>
        <span style={{fontSize:6,color:'rgba(255,255,255,.4)'}}>Principal</span>
      </div>
    </div>
  );
}

const DESIGNS = [
  { id:'h1', label:'Horizontal Classic', orientation:'H', component: CardH1 },
  { id:'h2', label:'Horizontal Banner',  orientation:'H', component: CardH2 },
  { id:'h3', label:'Horizontal Dark',    orientation:'H', component: CardH3 },
  { id:'v1', label:'Vertical Classic',   orientation:'V', component: CardV1 },
  { id:'v2', label:'Vertical Circle',    orientation:'V', component: CardV2 },
  { id:'v3', label:'Vertical Dark',      orientation:'V', component: CardV3 },
];

function printCards(students, design, theme, school) {
  const CardComp = design.component;
  const isV = design.orientation === 'V';
  const cardW = isV ? 210 : 340;
  const cardH = isV ? 320 : 210;
  const cols  = isV ? 3 : 2;
  const rows  = Math.ceil(students.length / cols);

  const win = window.open('','_blank','width=900,height=700');
  const ReactDOMServer = require ? null : null;

  win.document.write(`<!DOCTYPE html><html><head><meta charset="utf-8"/><title>ID Cards</title>
<style>
*{margin:0;padding:0;box-sizing:border-box;}
body{background:#f5f5f5;padding:20px;font-family:Arial,sans-serif;}
.grid{display:grid;grid-template-columns:repeat(${cols},${cardW}px);gap:16px;justify-content:center;}
@media print{
  @page{size:A4;margin:8mm;}
  body{background:#fff;padding:0;}
  .grid{gap:8px;}
