  ${isV ? `
  div.innerHTML = \`<div style="width:${cardW}px;height:${cardH}px;border-radius:14px;overflow:hidden;background:#fff;box-shadow:0 6px 24px rgba(0,0,0,.18);font-family:Arial,sans-serif;display:flex;flex-direction:column;">
    <div style="background:\${t.primary};padding:10px 12px;text-align:center;">\${school.logo?'<img src="'+school.logo+'" style="height:24px;object-fit:contain;margin-bottom:3px"/>':''}
      <div style="font-size:10px;font-weight:800;color:#fff;text-transform:uppercase;">\${school.schoolName||'School'}</div>
      <div style="font-size:6px;color:rgba(255,255,255,.6);">STUDENT IDENTITY CARD</div>
    </div>
    <div style="padding:10px;display:flex;justify-content:center;">
      <div style="width:68px;height:74px;border-radius:10px;overflow:hidden;border:3px solid \${t.primary};display:flex;align-items:center;justify-content:center;background:\${t.bg};">\${photo}</div>
    </div>
    <div style="text-align:center;padding:0 8px 6px;">
      <div style="font-size:13px;font-weight:800;color:#111827;">\${name}</div>
      <div style="font-size:9px;color:\${t.primary};font-weight:700;">\${student.class_name||'—'}\${student.section_name?' · Sec '+student.section_name:''}</div>
    </div>
    <div style="flex:1;padding:0 10px;font-size:8px;">
      \${[['Adm No',student.admission_no||'—'],['Roll No',student.roll_no||'—'],['Blood',student.blood_group||'—'],['DOB',student.date_of_birth?(student.date_of_birth+'').slice(0,10):'—'],['Parent',student.parent_name||'—'],['Phone',student.parent_phone||'—']].map(([k,v])=>'<div style="display:flex;justify-content:space-between;border-bottom:0.5px solid #F3F4F6;padding-bottom:2px;margin-bottom:2px;"><span style="color:#9CA3AF;font-weight:700;">'+k+'</span><span style="font-weight:700;color:#111827;">'+v+'</span></div>').join('')}
    </div>
    <div style="background:\${t.bg};padding:5px 10px;text-align:center;">
      <div style="font-size:6px;color:\${t.text};border-top:1px solid \${t.primary};padding-top:3px;display:inline-block;min-width:70px;">Principal</div>
      <div style="font-size:6px;color:\${t.text};">Valid: ${new Date().getFullYear()}-${new Date().getFullYear()+1}</div>
    </div>
  </div>\`;` : `
  div.innerHTML = \`<div style="width:${cardW}px;height:${cardH}px;border-radius:14px;overflow:hidden;display:flex;background:#fff;box-shadow:0 6px 24px rgba(0,0,0,.18);font-family:Arial,sans-serif;">
    <div style="width:90px;background:\${t.primary};display:flex;flex-direction:column;align-items:center;justify-content:space-between;padding:10px 6px;">
      <div style="text-align:center;">\${school.logo?'<img src="'+school.logo+'" style="width:36px;height:36px;object-fit:contain;border-radius:5px;margin-bottom:3px"/>':''}
        <div style="font-size:6px;font-weight:700;color:rgba(255,255,255,.8);text-transform:uppercase;">\${school.schoolName||'School'}</div>
      </div>
      <div style="width:66px;height:70px;border-radius:8px;background:rgba(255,255,255,.15);overflow:hidden;border:2px solid rgba(255,255,255,.3);display:flex;align-items:center;justify-content:center;">\${photo}</div>
      <div style="font-size:6px;color:rgba(255,255,255,.5);">STUDENT ID</div>
