          \${[['Class',student.class_name||'—'],['Sec',student.section_name||'A'],['Adm No',student.admission_no||'—'],['Roll',student.roll_no||'—'],['DOB',(student.date_of_birth||'').slice(0,10)||'—'],['Blood',student.blood_group||'—']].map(([k,v])=>'<div><span style="color:#9CA3AF;font-weight:700;">'+k+': </span><span style="font-weight:700;color:#111827;">'+v+'</span></div>').join('')}
        </div>
        \${student.parent_name?'<div style="margin-top:3px;font-size:8px;color:#6B7280;">Parent: <strong>'+student.parent_name+'</strong></div>':''}
        \${student.parent_phone?'<div style="font-size:8px;color:#6B7280;">Ph: '+student.parent_phone+'</div>':''}
