        <div style="font-size:6px;color:\${t.primary};font-weight:700;border-top:1px solid \${t.primary};padding-top:2px;">Principal</div>
      </div>
    </div>
  </div>\`;`}
  document.getElementById('cards').appendChild(div);
});
</script>
</body></html>`);
  win.document.close();
}

// ── MAIN COMPONENT ───────────────────────────────────────────
export default function IDCard() {
  const [students,    setStudents]    = useState([]);
  const [search,      setSearch]      = useState('');
  const [filterClass, setFilterClass] = useState('');
  const [classes,     setClasses]     = useState([]);
  const [loading,     setLoading]     = useState(false);
  const [selDesign,   setSelDesign]   = useState('h1');
  const [selTheme,    setSelTheme]    = useState('classic');
  const [selected,    setSelected]    = useState(new Set());
  const [school,      setSchool]      = useState({});
  const [previewStu,  setPreviewStu]  = useState(null);

  useEffect(() => {
    try { setSchool(JSON.parse(localStorage.getItem('school_settings'))||{}); } catch {}
    schoolAPI.getClasses().then(r=>setClasses(r.data.data||[])).catch(()=>{});
  }, []);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const res = await studentAPI.getAll({ limit:200, search:search||undefined, className:filterClass||undefined });
      const data = res.data.data||[];
      setStudents(data);
      if (!previewStu && data.length) setPreviewStu(data[0]);
    } catch { setStudents([]); }
    finally { setLoading(false); }
  }, [search, filterClass]);

  useEffect(() => { load(); }, [load]);

  const toggleSelect = (id) => {
    setSelected(prev => {
      const n = new Set(prev);
      n.has(id) ? n.delete(id) : n.add(id);
      return n;
    });
  };

  const design = DESIGNS.find(d=>d.id===selDesign)||DESIGNS[0];
  const CardComp = design.component;
  const selectedStudents = students.filter(s => selected.has(s.id));

  const inp = { padding:'9px 12px', border:'1.5px solid #E5E7EB', borderRadius:9, fontSize:13, outline:'none', fontFamily:'inherit', background:'#fff', boxSizing:'border-box' };

  return (
    <div>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:16}}>
        <div>
          <h2 style={{fontSize:20,fontWeight:700,color:'#111827'}}>ID Card Generator</h2>
          <p style={{fontSize:12,color:'#6B7280',marginTop:2}}>{students.length} students · {selected.size} selected</p>
        </div>
        <div style={{display:'flex',gap:10}}>
          {selected.size > 0 && (
            <button onClick={()=>printCards(selectedStudents, design, selTheme, school)}
              style={{padding:'10px 20px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:10,fontSize:13,fontWeight:700,cursor:'pointer'}}>
              🖨️ Print {selected.size} Card{selected.size>1?'s':''}
            </button>
          )}
          {previewStu && (
            <button onClick={()=>printCards([previewStu], design, selTheme, school)}
              style={{padding:'10px 18px',border:'1.5px solid #1E1B4B',background:'#fff',color:'#1E1B4B',borderRadius:10,fontSize:13,fontWeight:600,cursor:'pointer'}}>
              🖨️ Print Preview
            </button>
          )}
        </div>
      </div>

      <div style={{display:'grid',gridTemplateColumns:'320px 1fr',gap:16}}>
        {/* Left — Controls */}
        <div style={{display:'flex',flexDirection:'column',gap:12}}>
          {/* Design selector */}
          <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,padding:14}}>
            <div style={{fontWeight:700,fontSize:13,marginBottom:10,color:'#111827'}}>Card Design</div>
            <div style={{marginBottom:10}}>
              <div style={{fontSize:10,fontWeight:700,color:'#9CA3AF',textTransform:'uppercase',marginBottom:6}}>Horizontal</div>
              <div style={{display:'flex',gap:6}}>
                {DESIGNS.filter(d=>d.orientation==='H').map(d=>(
                  <button key={d.id} onClick={()=>setSelDesign(d.id)}
                    style={{flex:1,padding:'7px 4px',border:'1.5px solid '+(selDesign===d.id?'#1E1B4B':'#E5E7EB'),borderRadius:8,background:selDesign===d.id?'#EDE9F8':'#fff',fontSize:10,fontWeight:selDesign===d.id?700:400,cursor:'pointer',color:selDesign===d.id?'#1E1B4B':'#374151'}}>
                    {d.label.replace('Horizontal ','')}
                  </button>
                ))}
              </div>
            </div>
            <div>
              <div style={{fontSize:10,fontWeight:700,color:'#9CA3AF',textTransform:'uppercase',marginBottom:6}}>Vertical</div>
              <div style={{display:'flex',gap:6}}>
                {DESIGNS.filter(d=>d.orientation==='V').map(d=>(
                  <button key={d.id} onClick={()=>setSelDesign(d.id)}
                    style={{flex:1,padding:'7px 4px',border:'1.5px solid '+(selDesign===d.id?'#1E1B4B':'#E5E7EB'),borderRadius:8,background:selDesign===d.id?'#EDE9F8':'#fff',fontSize:10,fontWeight:selDesign===d.id?700:400,cursor:'pointer',color:selDesign===d.id?'#1E1B4B':'#374151'}}>
                    {d.label.replace('Vertical ','')}
                  </button>
                ))}
              </div>
            </div>
          </div>

          {/* Theme selector */}
          <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,padding:14}}>
            <div style={{fontWeight:700,fontSize:13,marginBottom:10,color:'#111827'}}>Color Theme</div>
            <div style={{display:'grid',gridTemplateColumns:'repeat(3,1fr)',gap:6}}>
              {Object.entries(THEMES).map(([key,t])=>(
                <button key={key} onClick={()=>setSelTheme(key)}
                  style={{padding:'8px 6px',border:'2px solid '+(selTheme===key?t.primary:'#E5E7EB'),borderRadius:8,background:t.bg,cursor:'pointer',display:'flex',alignItems:'center',gap:6}}>
                  <div style={{width:14,height:14,borderRadius:3,background:t.primary,flexShrink:0}}/>
                  <span style={{fontSize:9,fontWeight:700,color:t.primary}}>{t.name}</span>
                </button>
              ))}
            </div>
          </div>

          {/* Student search */}
          <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,padding:14}}>
            <div style={{fontWeight:700,fontSize:13,marginBottom:10,color:'#111827'}}>Select Students</div>
            <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="🔍 Search…" style={{...inp,width:'100%',marginBottom:8}}/>
            <select value={filterClass} onChange={e=>setFilterClass(e.target.value)} style={{...inp,width:'100%',marginBottom:10}}>
              <option value="">All Classes</option>
              {classes.map(c=><option key={c.id} value={c.name}>{c.name}</option>)}
            </select>
            <div style={{display:'flex',gap:6,marginBottom:8}}>
              <button onClick={()=>setSelected(new Set(students.map(s=>s.id)))}
                style={{flex:1,padding:'6px',border:'1px solid #E5E7EB',borderRadius:7,background:'#F9FAFB',fontSize:11,cursor:'pointer',fontWeight:600}}>
                ☑ All
              </button>
              <button onClick={()=>setSelected(new Set())}
                style={{flex:1,padding:'6px',border:'1px solid #E5E7EB',borderRadius:7,background:'#F9FAFB',fontSize:11,cursor:'pointer',fontWeight:600}}>
                ☐ Clear
              </button>
            </div>
            <div style={{maxHeight:240,overflowY:'auto',border:'1px solid #F3F4F6',borderRadius:8}}>
              {loading ? <div style={{padding:16,textAlign:'center',color:'#9CA3AF'}}>⏳</div>
                : students.map(s=>(
                  <div key={s.id} onClick={()=>{toggleSelect(s.id);setPreviewStu(s);}}
                    style={{display:'flex',alignItems:'center',gap:8,padding:'7px 10px',borderBottom:'0.5px solid #F9FAFB',cursor:'pointer',background:selected.has(s.id)?'#EDE9F8':'#fff',transition:'background .1s'}}
                    onMouseEnter={e=>{if(!selected.has(s.id))e.currentTarget.style.background='#F5F3FF';}}
                    onMouseLeave={e=>{if(!selected.has(s.id))e.currentTarget.style.background='#fff';}}>
                    <input type="checkbox" checked={selected.has(s.id)} onChange={()=>{}} style={{accentColor:'#1E1B4B'}}/>
                    {s.photo_url
                      ? <img src={s.photo_url} style={{width:26,height:26,borderRadius:'50%',objectFit:'cover'}}/>
                      : <div style={{width:26,height:26,borderRadius:'50%',background:'#EDE9F8',display:'flex',alignItems:'center',justifyContent:'center',fontSize:11,fontWeight:700,color:'#1E1B4B',flexShrink:0}}>{(s.first_name||'?')[0]}</div>}
                    <div style={{flex:1,minWidth:0}}>
                      <div style={{fontSize:11,fontWeight:600,color:'#111827',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{s.first_name} {s.last_name||''}</div>
                      <div style={{fontSize:9,color:'#9CA3AF'}}>{s.admission_no} · {s.class_name||'—'}</div>
                    </div>
                  </div>
                ))
              }
            </div>
          </div>
        </div>

        {/* Right — Preview */}
        <div>
          <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,padding:16,marginBottom:14}}>
            <div style={{fontWeight:700,fontSize:13,marginBottom:12,color:'#111827',display:'flex',justifyContent:'space-between',alignItems:'center'}}>
              <span>Preview — {design.label}</span>
              <span style={{fontSize:11,color:'#9CA3AF'}}>{design.orientation==='H'?'Landscape':'Portrait'}</span>
            </div>
            <div style={{display:'flex',gap:16,alignItems:'flex-start',justifyContent:'center',flexWrap:'wrap',padding:'10px 0'}}>
              {/* Front */}
              <div style={{textAlign:'center'}}>
                <div style={{fontSize:10,color:'#9CA3AF',marginBottom:8,fontWeight:600}}>FRONT</div>
                <CardComp student={previewStu} theme={selTheme} school={school}/>
              </div>
            </div>
          </div>

          {/* Selected cards mini grid */}
          {selected.size > 0 && (
            <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,padding:14}}>
              <div style={{fontWeight:700,fontSize:13,marginBottom:10,color:'#111827'}}>Selected Cards ({selected.size})</div>
              <div style={{display:'flex',gap:10,flexWrap:'wrap',maxHeight:300,overflowY:'auto'}}>
                {selectedStudents.map(s=>(
                  <div key={s.id} style={{transform:'scale(0.4)',transformOrigin:'top left',marginBottom: design.orientation==='V'?-190:-128,marginRight:design.orientation==='V'?-130:-210,flexShrink:0}}>
                    <CardComp student={s} theme={selTheme} school={school}/>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
